//将数字转换成中文金额
function convertToChineseCurrency(num) {
  const strOutputDigits = '零壹贰叁肆伍陆柒捌玖';
  const strOutputUnits = '个拾佰仟万拾佰仟亿拾佰仟万';
  const strUnits = '角分';
  const strRegex = /^\d+(\.\d+)?$/;
  let leftNum = Math.floor(num);
  let rightNum = Math.round((num - leftNum) * 100); // 处理小数部分，乘以100四舍五入
  let output = '';

  if (num < 1) {
    output = '零';
  }

  // 处理整数部分
  let strOutput = '';
  for (let i = 0; i < strOutputUnits.length && leftNum > 0; i++) {
    output = strOutputDigits.charAt(leftNum % 10) + output;
    if(i > 0 && output !== '零'){
      output = strOutputUnits.charAt(i) + output;
    }
    leftNum = Math.floor(leftNum / 10);
  }

  output = output.replace(/零(仟|佰|拾|角)/g, '零').replace(/(零)+/g, '零').replace(/零(万|亿|个)/g, '$1');
  output = output.replace(/^个/, '');

  // 处理小数部分
  if (rightNum > 0) {
    output += output ? '元' : '';
    if (rightNum < 10) {
      output += '零';
    }
    strOutput = '';
    for (let i = 0; i < strUnits.length && rightNum > 0; i++) {
      strOutput = strOutputDigits.charAt(rightNum % 10) + strOutput;
      if(i > 0 || strOutput !== '零'){
        strOutput = strUnits.charAt(i) + strOutput;
      }
      rightNum = Math.floor(rightNum / 10);
    }
    output += strOutput;
  } else {
    output += output ? '元整' : '';
  }

  return output.replace(/^\s+|\s+$/g, '').replace(/零分$/, '整');
}

